#include <stdio.h>
#include <unistd.h>
#include <sys/wait.h>

int main() {
 pid_t pid = vfork();

 if (pid == 0) {
 // Child process
 printf("Child: About to exec\n");
 execl("/bin/ls", "ls", "-l", NULL);

 // Only reached if exec fails
 perror("execl failed");
 _exit(1);
 } else if (pid > 0) {
 // Parent process
 printf("Parent: Child PID = %d\n", pid);
 wait(NULL); // Wait for child
 printf("Child completed\n");
 } else {
 // Error
 perror("vfork failed");
 return 1;
 }
 return 0;
}

#include <stdio.h>
#include <unistd.h>
#include <sys/wait.h>

int main() {
 pid_t pid = vfork();

 if (pid == 0) {
 // Child process - just exit without exec
 // MUST use _exit() not exit()
 printf("Child: Exiting directly\n");
 _exit(0); // Use _exit() not exit()!
 } else if (pid > 0) {
 wait(NULL);
 printf("Parent: Child exited\n");
 }
 return 0;
}

// WRONG CODE - DO NOT USE
int main() {
 int x = 10;
 pid_t pid = vfork();

 if (pid == 0) {
 x = 20; // DANGEROUS! Modifies parent's variable
 // No exec() called - UNDEFINED BEHAVIOR
 return 0; // EVEN WORSE! Corrupts parent's stack
 }
 wait(NULL);
 printf("x = %d\n", x); // Unpredictable!
 return 0;
}

// fork() - Safe but slower
pid_t p1 = fork();
if (p1 == 0) {
 // Child has its own address space
 // Can modify freely without affecting parent
 printf("Child: x = %d\n", ++x);
 exit(0);
}

// vfork() - Fast but dangerous
pid_t p2 = vfork();
if (p2 == 0) {
 // Child shares parent's address space
 // MUST call exec() immediately
 execl("/bin/program", "program", NULL);
 _exit(1);
}
